var accel     = msg.payload.acceleration || 0;
var tilt      = msg.payload.tilt_angle   || 0;
var vibration = msg.payload.vibration    || 0;
var pressure  = msg.payload.pressure     || 0;
var latitude  = msg.payload.latitude     || 21.145800;
var longitude = msg.payload.longitude    || 79.088200;

var highAccel = accel > 2.5;
var highTilt  = tilt  > 60.0;
var vibHit    = vibration === 1;
var accident  = highAccel && highTilt && vibHit;

var severity = 'NORMAL';
if (accident) {
    severity = accel > 4.0 ? 'HIGH' : 'MEDIUM';
}

msg.payload = {
    acceleration : accel,
    tilt_angle   : tilt,
    vibration    : vibration,
    pressure     : pressure,
    latitude     : latitude,
    longitude    : longitude,
    accident     : accident,
    severity     : severity,
    maps_link    : 'https://maps.google.com/?q=' + latitude + ',' + longitude,
    device_id    : msg.payload.device_id || 'SmartHelmet_Arduino',
    frame        : msg.payload.frame     || 0
};

msg.accident = accident;
return msg;

var p = msg.payload;
var lat = p.latitude  || 21.145800;
var lng = p.longitude || 79.088200;

msg.payload = {
    acceleration : p.acceleration || 0,
    tilt_angle   : p.tilt_angle   || 0,
    vibration    : 1,
    pressure     : p.pressure     || 0,
    latitude     : lat,
    longitude    : lng,
    accident     : true,
    severity     : p.severity     || 'HIGH',
    device_id    : p.device_id    || 'SmartHelmet_Arduino',
    maps_link    : 'https://maps.google.com/?q=' + lat + ',' + lng,
    message      : 'ACCIDENT DETECTED - Emergency Alert'
};
msg.accident = true;
return msg;

var p = msg.payload;
var lat = p.latitude  || 21.145800;
var lng = p.longitude || 79.088200;

// ThingsBoard Create Alarm API payload
msg.alarm = {
    type     : 'Accident Detected',
    severity : p.acceleration > 4.0 ? 'CRITICAL' : 'MAJOR',
    status   : 'ACTIVE_UNACK',
    details  : {
        acceleration : p.acceleration,
        tilt_angle   : p.tilt_angle,
        vibration    : p.vibration,
        pressure     : p.pressure,
        latitude     : lat,
        longitude    : lng,
        maps_link    : 'https://maps.google.com/?q=' + lat + ',' + lng,
        severity     : p.severity,
        device_id    : p.device_id || 'SmartHelmet_Arduino'
    }
};

msg.payload = msg.alarm;

msg.headers = {
    'Content-Type'  : 'application/json',
    'X-Authorization': 'Bearer YOUR_JWT_TOKEN_HERE'
};

return msg;

var https = context.get('https');
var p = msg.payload;

var data;
if (p.accident === true) {
    data = JSON.stringify({
        acceleration : p.acceleration || 4.52,
        tilt_angle   : p.tilt_angle   || 88.7,
        vibration    : 1,
        pressure     : p.pressure     || 870,
        latitude     : p.latitude     || 21.145800,
        longitude    : p.longitude    || 79.088200,
        accident     : true,
        severity     : p.severity     || 'HIGH',
        maps_link    : 'https://maps.google.com/?q=' + (p.latitude||21.145800) + ',' + (p.longitude||79.088200)
    });
} else {
    data = JSON.stringify({
        acceleration : p.acceleration || 1.02,
        tilt_angle   : p.tilt_angle   || 5.3,
        vibration    : p.vibration    || 0,
        pressure     : p.pressure     || 300,
        latitude     : p.latitude     || 21.145800,
        longitude    : p.longitude    || 79.088200,
        accident     : false,
        severity     : 'NORMAL',
        maps_link    : 'https://maps.google.com/?q=' + (p.latitude||21.145800) + ',' + (p.longitude||79.088200)
    });
}

var options = {
    hostname           : 'thingsboard.cloud',
    port               : 443,
    path               : '/api/v1/ytavwytpxn2jcnylxbvf/telemetry',
    method             : 'POST',
    rejectUnauthorized : false,
    headers            : {
        'Content-Type'   : 'application/json',
        'Content-Length' : Buffer.byteLength(data)
    }
};

var req = https.request(options, function(res) {
    var body = '';
    res.on('data', function(chunk) { body += chunk; });
    res.on('end',  function() {
        node.send({ payload: 'ThingsBoard OK: ' + res.statusCode + ' — ' + body });
    });
});

req.on('error', function(e) {
    node.send({ payload: 'ThingsBoard ERROR: ' + e.message });
});

req.write(data);
req.end();
return null;
